import{_ as e,o as a,c as d,a2 as o}from"./chunks/framework.CQMe4Urg.js";const m=JSON.parse('{"title":"第五章 Tool Use -- 让 LLM 长出手脚","description":"","frontmatter":{},"headers":[],"relativePath":"05-tool-use/index.md","filePath":"05-tool-use/index.md","lastUpdated":1776333512000}'),r={name:"05-tool-use/index.md"};function l(i,t,n,h,s,u){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="第五章-tool-use-让-llm-长出手脚" tabindex="-1">第五章 Tool Use -- 让 LLM 长出手脚 <a class="header-anchor" href="#第五章-tool-use-让-llm-长出手脚" aria-label="Permalink to &quot;第五章 Tool Use -- 让 LLM 长出手脚&quot;">​</a></h1><p>大语言模型很聪明，但它只是一个&quot;大脑&quot;：能思考、能推理、能生成文字，却没有手脚。它不能上网查天气，不能执行代码，不能发邮件，甚至不知道现在几点。</p><p><strong>Tool Use（工具使用）就是给 LLM 装上手脚的技术。</strong> 你告诉模型&quot;这里有一些工具可以用&quot;，模型在需要时会生成一段结构化的调用请求（JSON），你的程序负责真正执行，再把结果喂回给模型。模型扮演决策者，程序扮演执行者，两者配合完成任务。</p><p>这一章从最基础的工具定义讲起，经过完整的调用流程和多工具协同，最后到动态工具生成和安全沙箱等高级话题。学完之后，你将能够为 LLM 配备任意能力，为后面构建真正的 Agent 打下坚实基础。</p><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><ul><li><a href="./beginner.html">入门篇</a> -- 什么是 Tool Use、JSON Schema 工具定义、完整的 8 步调用流程、天气查询实战</li><li><a href="./intermediate.html">进阶篇</a> -- 并行工具调用、链式调用、模型如何选择工具、工具数量的影响与应对</li><li><a href="./advanced.html">高级篇</a> -- 动态工具生成、工具结果缓存、工具路由策略、安全沙箱设计</li></ul><h2 id="核心概念速览" tabindex="-1">核心概念速览 <a class="header-anchor" href="#核心概念速览" aria-label="Permalink to &quot;核心概念速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>一句话解释</th></tr></thead><tbody><tr><td>Tool Use / Function Calling</td><td>让 LLM 能调用外部函数的机制</td></tr><tr><td>JSON Schema</td><td>描述工具参数结构的标准格式</td></tr><tr><td><code>stop_reason: &quot;tool_use&quot;</code></td><td>模型表示&quot;我需要调用工具&quot;的信号</td></tr><tr><td><code>tool_result</code></td><td>你把工具执行结果返回给模型的消息</td></tr><tr><td>并行调用</td><td>模型一次请求多个独立工具，可同时执行</td></tr><tr><td>链式调用</td><td>工具 A 的结果作为工具 B 的输入，模型自动编排</td></tr><tr><td>动态工具</td><td>根据上下文动态生成工具列表，而非固定注册</td></tr><tr><td>Human-in-the-Loop</td><td>高风险操作前加入人类确认环节</td></tr></tbody></table><h2 id="学完你能做到" tabindex="-1">学完你能做到 <a class="header-anchor" href="#学完你能做到" aria-label="Permalink to &quot;学完你能做到&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>能力</th></tr></thead><tbody><tr><td>入门</td><td>定义工具 Schema、跑通完整的 Tool Use 8 步流程、构建天气查询 Agent</td></tr><tr><td>进阶</td><td>管理多工具并行/链式调用、处理工具执行失败、构建多功能助手</td></tr><tr><td>高级</td><td>动态生成工具列表、设计工具路由和缓存策略、实现 Human-in-the-Loop 安全机制</td></tr></tbody></table><h2 id="前置知识" tabindex="-1">前置知识 <a class="header-anchor" href="#前置知识" aria-label="Permalink to &quot;前置知识&quot;">​</a></h2><ul><li>已完成前面章节，能够用 Anthropic SDK 发送基础请求</li><li>理解 JSON 基本语法</li><li>有 Python 基础</li></ul>',12)])])}const _=e(r,[["render",l]]);export{m as __pageData,_ as default};
